export interface SurveyInput {
    name: string;
    status?: SurveyStatus;
    questions: {
        [key: string]: SurveyQuestion;
    };
    paths?: string[];
}
export interface Survey extends SurveyInput {
    id: string;
    appName: string;
    status: SurveyStatus;
    createdBy: string;
    updatedBy?: string;
    createdOn: number;
    updatedOn?: number;
}
export interface SurveyQuestion {
    id: string;
    order: number;
    type: SurveyQuestionType;
    question: string;
    answers: string[];
}
export declare enum SurveyQuestionType {
    RATING = "RATING"
}
export declare enum SurveyStatus {
    ACTIVE = "ACTIVE",
    INACTIVE = "INACTIVE"
}
export interface SurveyUserAnswerInput {
    id: string;
    optedOut?: boolean;
    answers?: {
        [key: string]: string;
    };
}
export interface SurveyUserAnswer extends SurveyUserAnswerInput {
    id: string;
    appName: string;
    userId: string;
    updatedOn: number;
    answers: {
        [key: string]: string;
    };
}
export interface SurveyResult {
    id: string;
    appName: string;
    questions: {
        [key: string]: {
            answers: {
                [key: string]: number;
            };
        };
    };
}
